  resumenes: { label: 'Resúmenes',  icon: '📄', empty: 'No hay resúmenes disponibles aún.' },
  videoclase:{ label: 'Videoclase', icon: '🎬', empty: 'No hay videoclases disponibles aún.' },
  kahoot:    { label: 'Kahoot',     icon: '🎯', empty: 'Kahoot próximamente disponible.' },
