function startQuiz(spId, section, topicNum) {
  const topicData = ((QUIZ_DATA[spId] || {})[section] || {})[String(topicNum)];
  if (!topicData || !topicData.questions.length) return;

  const stateKey = `${spId}_${section}_${topicNum}`;
  quizState[stateKey] = {
    spId, section, topicNum,
    questions: [...topicData.questions],
    current: 0,
    score: 0,
    answered: false,
  };

  renderQuizQuestion(spId, section, stateKey);
}

function renderQuizQuestion(spId, section, stateKey) {
  const state = quizState[stateKey];
  const container = document.getElementById(spId + '-content');
  if (!container) return;

  const topicData  = ((QUIZ_DATA[spId] || {})[section] || {})[String(state.topicNum)];
  const cfg        = SPECIALTY_CONFIG[spId];
  const q          = state.questions[state.current];
  const total      = state.questions.length;
  const current    = state.current + 1;
  const progress   = (current / total) * 100;
  const isKahoot   = section === 'kahoot';

  const COLORS = ['--color-a:#e74c3c', '--color-b:#3498db', '--color-c:#27ae60', '--color-d:#f39c12'];
  const ICONS  = ['▲', '●', '■', '♦'];
  const LABELS = ['A', 'B', 'C', 'D'];
  const OPTS   = [q.a, q.b, q.c, q.d];

  container.innerHTML = `
    <div class="quiz-session ${isKahoot ? 'quiz-kahoot' : 'quiz-simulador'}">
      <!-- Header -->
      <div class="qs-header">
        <button class="qs-back" onclick="exitQuiz('${spId}','${section}','${stateKey}')">← Volver</button>
        <div class="qs-info">
          <span class="qs-topic">${topicData.name}</span>
          <span class="qs-badge">${isKahoot ? '🎯 Kahoot' : '📝 Simulador'}</span>
        </div>
        <div class="qs-score">
          <span class="qs-score-num">${state.score}</span>
          <span class="qs-score-label">pts</span>
        </div>
      </div>

      <!-- Progress bar -->
      <div class="qs-progress-wrap">
        <div class="qs-progress-bar" style="width:${progress}%"></div>
        <span class="qs-progress-text">${current} / ${total}</span>
      </div>

      <!-- Question -->
      <div class="qs-question-card ${isKahoot ? '' : 'qs-clinical'}">
        <div class="qs-q-num">Pregunta ${current}</div>
        <div class="qs-q-text">${q.q}</div>
      </div>

      <!-- Options -->
      <div class="qs-options ${isKahoot ? 'qs-options--grid' : 'qs-options--list'}">
        ${OPTS.map((opt, i) => `
          <button
            class="qs-option ${isKahoot ? 'qs-option--kahoot' : 'qs-option--list'}"
            style="${COLORS[i]}"
            data-choice="${LABELS[i]}"
            onclick="answerQuestion('${stateKey}', '${LABELS[i]}', this)"
          >
            <span class="qs-opt-icon">${isKahoot ? ICONS[i] : LABELS[i]}</span>
            <span class="qs-opt-text">${opt}</span>
          </button>
        `).join('')}
      </div>

      <!-- Feedback (hidden initially) -->
      <div class="qs-feedback" id="qs-feedback-${stateKey}" style="display:none">
        <div class="qs-feedback-inner">
          <div class="qs-feedback-icon" id="qs-fb-icon-${stateKey}"></div>
          <div class="qs-feedback-msg" id="qs-fb-msg-${stateKey}"></div>
          <button class="qs-next-btn" id="qs-next-btn-${stateKey}" onclick="nextQuestion('${stateKey}')">
            ${current < total ? 'Siguiente →' : 'Ver resultados 🏆'}
          </button>
        </div>
      </div>
    </div>
  `;
}

function answerQuestion(stateKey, choice, btn) {
  const state = quizState[stateKey];
  if (state.answered) return;
  state.answered = true;

  const q       = state.questions[state.current];
  const correct = q.ans;
  const isRight = choice === correct;

  if (isRight) state.score++;

  // Color all buttons
  const allBtns = btn.closest('.qs-options').querySelectorAll('.qs-option');
  allBtns.forEach(b => {
    const bChoice = b.dataset.choice;
    if (bChoice === correct) {
      b.classList.add('correct');
    } else if (bChoice === choice && !isRight) {
      b.classList.add('wrong');
    } else {
      b.classList.add('dimmed');
    }
    b.disabled = true;
  });

  // Show feedback
  const fb     = document.getElementById(`qs-feedback-${stateKey}`);
  const fbIcon = document.getElementById(`qs-fb-icon-${stateKey}`);
  const fbMsg  = document.getElementById(`qs-fb-msg-${stateKey}`);
  const fbBtn  = document.getElementById(`qs-next-btn-${stateKey}`);

  fb.style.display = 'flex';
  if (isRight) {
    fb.classList.add('fb-correct');
    fbIcon.textContent = '✓';
    fbMsg.textContent  = '¡Correcto!';
  } else {
    fb.classList.add('fb-wrong');
    fbIcon.textContent = '✗';
    fbMsg.innerHTML    = `Incorrecto. La respuesta correcta es <strong>${correct}</strong>: ${q[correct.toLowerCase()]}`;
  }

  // Update score display
  const scoreEl = document.querySelector('.qs-score-num');
  if (scoreEl) scoreEl.textContent = state.score;

  const total = state.questions.length;
  const next  = state.current + 1;
  fbBtn.textContent = next < total ? 'Siguiente →' : 'Ver resultados 🏆';
}

function nextQuestion(stateKey) {
  const state = quizState[stateKey];
  state.current++;
  state.answered = false;

  if (state.current >= state.questions.length) {
    showResults(stateKey);
  } else {
    renderQuizQuestion(state.spId, state.section, stateKey);
  }
}

function showResults(stateKey) {
  const state    = quizState[stateKey];
  const container = document.getElementById(state.spId + '-content');
  if (!container) return;

  const cfg      = SPECIALTY_CONFIG[state.spId];
  const topicData = ((QUIZ_DATA[state.spId] || {})[state.section] || {})[String(state.topicNum)];
  const total    = state.questions.length;
  const score    = state.score;
  const pct      = Math.round((score / total) * 100);
  const isKahoot = state.section === 'kahoot';

  let emoji, msg;
  if (pct >= 80)      { emoji = '🏆'; msg = '¡Excelente rendimiento!'; }
  else if (pct >= 60) { emoji = '👍'; msg = 'Buen trabajo, sigue practicando.'; }
  else if (pct >= 40) { emoji = '📖'; msg = 'Necesitas repasar este tema.'; }
  else                { emoji = '💪'; msg = 'Revisa el material y vuelve a intentarlo.'; }

  // Color ring
  const ringColor = pct >= 80 ? '#27ae60' : pct >= 60 ? '#f39c12' : '#e74c3c';

  container.innerHTML = `
    <div class="quiz-results">
      <div class="qr-card">
        <div class="qr-emoji">${emoji}</div>
        <h2 class="qr-title">Resultados</h2>
        <div class="qr-topic">${topicData.name}</div>

        <div class="qr-ring" style="--ring-color:${ringColor};--pct:${pct}">
          <svg viewBox="0 0 120 120">
            <circle cx="60" cy="60" r="50" fill="none" stroke="rgba(255,255,255,0.06)" stroke-width="10"/>
            <circle cx="60" cy="60" r="50" fill="none" stroke="${ringColor}"
              stroke-width="10"
              stroke-dasharray="${2*Math.PI*50}"
              stroke-dashoffset="${2*Math.PI*50*(1-pct/100)}"
              stroke-linecap="round"
              transform="rotate(-90 60 60)"
              style="transition:stroke-dashoffset 1s ease"
            />
          </svg>
          <div class="qr-ring-text">
            <span class="qr-pct">${pct}%</span>
            <span class="qr-score-label">${score}/${total}</span>
          </div>
        </div>

        <div class="qr-msg">${msg}</div>

        <div class="qr-actions">
          <button class="qr-btn qr-btn--retry" onclick="startQuiz('${state.spId}','${state.section}',${state.topicNum})">
            🔄 Reintentar
          </button>
          <button class="qr-btn qr-btn--back" onclick="exitQuiz('${state.spId}','${state.section}','${stateKey}')">
            ← Elegir otro tema
          </button>
        </div>
      </div>
    </div>
  `;
}

function exitQuiz(spId, section, stateKey) {
  delete quizState[stateKey];
  renderSpecialtySection(spId, section);
}



// ===========================
// SOUND ENGINE
// ===========================
let soundMuted = false;

function playSound(type) {
  if (soundMuted) return;
  try {
    const ctx = new (window.AudioContext || window.webkitAudioContext)();
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();
    osc.connect(gain);
    gain.connect(ctx.destination);

    if (type === 'correct') {
      // Two-tone rising chime
      osc.type = 'sine';
      osc.frequency.setValueAtTime(523.25, ctx.currentTime);      // C5
      osc.frequency.setValueAtTime(783.99, ctx.currentTime + 0.12); // G5
      gain.gain.setValueAtTime(0.35, ctx.currentTime);
      gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.5);
      osc.start(ctx.currentTime);
      osc.stop(ctx.currentTime + 0.5);
    } else if (type === 'wrong') {
      // Low descending tone
      osc.type = 'sawtooth';
      osc.frequency.setValueAtTime(220, ctx.currentTime);
      osc.frequency.setValueAtTime(150, ctx.currentTime + 0.15);
      gain.gain.setValueAtTime(0.25, ctx.currentTime);
      gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.4);
      osc.start(ctx.currentTime);
      osc.stop(ctx.currentTime + 0.4);
    } else if (type === 'flip') {
      // Soft click for card flip
      osc.type = 'sine';
      osc.frequency.setValueAtTime(900, ctx.currentTime);
      gain.gain.setValueAtTime(0.15, ctx.currentTime);
      gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.12);
      osc.start(ctx.currentTime);
      osc.stop(ctx.currentTime + 0.12);
    } else if (type === 'easy') {
      osc.type = 'sine';
      osc.frequency.setValueAtTime(660, ctx.currentTime);
      osc.frequency.setValueAtTime(880, ctx.currentTime + 0.08);
      gain.gain.setValueAtTime(0.2, ctx.currentTime);
      gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.25);
      osc.start(ctx.currentTime);
      osc.stop(ctx.currentTime + 0.25);
    } else if (type === 'hard') {
      osc.type = 'triangle';
      osc.frequency.setValueAtTime(300, ctx.currentTime);
      gain.gain.setValueAtTime(0.2, ctx.currentTime);
      gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.2);
      osc.start(ctx.currentTime);
      osc.stop(ctx.currentTime + 0.2);
    }
  } catch(e) { /* Audio not supported */ }
}

// Mute button
const muteBtn     = document.getElementById('muteBtn');
const muteBtnIcon = document.getElementById('muteBtnIcon');
if (muteBtn) {
  muteBtn.addEventListener('click', () => {
    soundMuted = !soundMuted;
    muteBtnIcon.textContent = soundMuted ? '🔇' : '🔊';
    muteBtn.classList.toggle('muted', soundMuted);
    muteBtn.title = soundMuted ? 'Activar sonido' : 'Silenciar sonido';
  });
}

// Patch answerQuestion to use sounds
const _origAnswerQuestion = answerQuestion;
answerQuestion = function(stateKey, choice, btn) {
  const state = quizState[stateKey];
  if (state && state.answered) return;
  // Determine correct before calling original
  const q = state.questions[state.current];
  const isRight = choice === q.ans;
  playSound(isRight ? 'correct' : 'wrong');
  _origAnswerQuestion(stateKey, choice, btn);
};

