const ankiState = {};

function renderAnki(container, spId) {
  const data  = (ANKI_DATA || {})[spId] || {};
  const cfg   = SPECIALTY_CONFIG[spId];
  const topics = Object.values(data).sort((a,b) => a.num - b.num);
  const hasPreview = SPECIALTIES_WITH_PREVIEW.includes(spId);

  if (topics.length === 0) {
    container.innerHTML = `<div class="empty-state"><div class="empty-icon">🃏</div><p>Tarjetas Anki próximamente para ${cfg.label}.</p></div>`;
    return;
  }

  const totalCards = topics.reduce((s,t) => s + t.cards.length, 0);

  container.innerHTML = `
    <div class="anki-topic-list">
      <div class="quiz-list-header">
        <div class="quiz-list-title">🃏 Tarjetas de Memoria — Estilo Anki</div>
        <div class="quiz-list-sub">${topics.length} temas · ${totalCards} tarjetas en total</div>
      </div>
      <div class="quiz-topic-grid">
        ${topics.map(t => {
          const { thumb: pvThumb, video: pvVideo } = hasPreview ? getTopicPreviewPaths(spId, t.num) : { thumb: '', video: '' };
          return `
          <div class="quiz-topic-card quiz-topic-card--anki" onclick="startAnki('${spId}',${t.num})" style="--accent:${cfg.accent}">
            ${hasPreview && pvThumb ? `
            <div class="qtc-thumb">
              <img class="cir-thumb-img" src="${pvThumb}" alt="Tema ${t.num}" loading="lazy" onerror="this.style.display='none'" />
              ${pvVideo ? `<video class="topic-hover-video" src="${pvVideo}" muted playsinline preload="none" loop></video>` : ''}
              <div class="qtc-thumb-overlay"></div>
            </div>` : ''}
            <div class="qtc-num" style="background:${cfg.accent}22;color:${cfg.accent}">${t.num}</div>
            <div class="qtc-name">${t.name}</div>
            <div class="qtc-count">${t.cards.length} tarjetas</div>
            <div class="qtc-play" style="background:${cfg.accent}22;color:${cfg.accent}">🃏 Estudiar</div>
          </div>`;
        }).join('')}
      </div>
    </div>
  `;

  if (hasPreview) {
    container.querySelectorAll('.quiz-topic-card').forEach(card => {
      const videoEl = card.querySelector('.topic-hover-video');
      if (!videoEl) return;
      card.addEventListener('mouseenter', () => videoEl.play().catch(() => {}));
      card.addEventListener('mouseleave', () => { videoEl.pause(); videoEl.currentTime = 0; });
    });
  }
}

function startAnki(spId, topicNum) {
  const topicData = ((ANKI_DATA || {})[spId] || {})[String(topicNum)];
  if (!topicData) return;

  const stateKey = `anki_${spId}_${topicNum}`;
  ankiState[stateKey] = {
    spId,
    topicNum,
    deck: [...topicData.cards],   // working deck
    done: [],                      // finished (easy) cards
    current: 0,
    flipped: false,
  };

  renderAnkiCard(spId, stateKey);
}

function renderAnkiCard(spId, stateKey) {
  const state    = ankiState[stateKey];
  const container = document.getElementById(spId + '-content');
  if (!container) return;

  const topicData = ((ANKI_DATA || {})[spId] || {})[String(state.topicNum)];
  const cfg       = SPECIALTY_CONFIG[spId];
  const total     = state.deck.length + state.done.length;
  const done      = state.done.length;
  const remaining = state.deck.length;

  if (remaining === 0) {
    renderAnkiComplete(spId, stateKey, topicData, total);
    return;
  }

  const card = state.deck[state.current % state.deck.length];
  const progress = done / total;

  container.innerHTML = `
    <div class="anki-session">
      <!-- Header -->
      <div class="qs-header">
        <button class="qs-back" onclick="exitAnki('${spId}','${stateKey}')">← Volver</button>
        <div class="qs-info">
          <span class="qs-topic">${topicData.name}</span>
          <span class="qs-badge anki-badge">🃏 Anki</span>
        </div>
        <div class="anki-counter">
          <span class="anki-remaining" title="Pendientes">${remaining} 📋</span>
          <span class="anki-done" title="Dominadas">${done} ✓</span>
        </div>
      </div>

      <!-- Progress -->
      <div class="qs-progress-wrap">
        <div class="qs-progress-bar anki-progress-bar" style="width:${progress*100}%;background:linear-gradient(90deg,#10b981,#34d399)"></div>
        <span class="qs-progress-text">${done}/${total} dominadas</span>
      </div>

      <!-- Card -->
      <div class="anki-card-scene" id="anki-scene-${stateKey}" onclick="flipAnkiCard('${stateKey}')">
        <div class="anki-card" id="anki-card-${stateKey}">
          <!-- FRONT -->
          <div class="anki-card-face anki-card-front" style="--accent:${cfg.accent}">
            <div class="anki-face-label">PREGUNTA</div>
            <div class="anki-face-text">${card.front}</div>
            <div class="anki-tap-hint">Toca para ver la respuesta ↓</div>
          </div>
          <!-- BACK -->
          <div class="anki-card-face anki-card-back" style="--accent:${cfg.accent}">
            <div class="anki-face-label">RESPUESTA</div>
            <div class="anki-face-text">${card.back}</div>
            <div class="anki-difficulty-btns" onclick="event.stopPropagation()">
              <button class="anki-btn anki-btn--hard" onclick="ankiHard('${stateKey}')">
                😓 Difícil<br><span>Repetir al final</span>
              </button>
              <button class="anki-btn anki-btn--easy" onclick="ankiEasy('${stateKey}')">
                😊 Fácil<br><span>Siguiente tarjeta</span>
              </button>
            </div>
          </div>
        </div>
      </div>

      <div class="anki-hint">
        <span>Haz clic en la tarjeta para voltearla • <strong>Difícil</strong> = repetir al final • <strong>Fácil</strong> = siguiente</span>
      </div>
    </div>
  `;
}

function flipAnkiCard(stateKey) {
  const state = ankiState[stateKey];
  if (!state) return;

  const card = document.getElementById(`anki-card-${stateKey}`);
  if (!card) return;

  state.flipped = !state.flipped;
  card.classList.toggle('is-flipped', state.flipped);
  playSound('flip');
}

function ankiEasy(stateKey) {
  const state = ankiState[stateKey];
  if (!state) return;

  // Remove current card from deck
  const idx = state.current % state.deck.length;
  const [card] = state.deck.splice(idx, 1);
  state.done.push(card);
  state.flipped = false;
  playSound('easy');

  renderAnkiCard(state.spId, stateKey);
}

function ankiHard(stateKey) {
  const state = ankiState[stateKey];
  if (!state) return;

  // Move card to end of deck
  const idx = state.current % state.deck.length;
  const [card] = state.deck.splice(idx, 1);
  state.deck.push(card);
  state.flipped = false;
  playSound('hard');

  renderAnkiCard(state.spId, stateKey);
}

function renderAnkiComplete(spId, stateKey, topicData, total) {
  const container = document.getElementById(spId + '-content');
  if (!container) return;
  const cfg = SPECIALTY_CONFIG[spId];

  container.innerHTML = `
    <div class="quiz-results">
      <div class="qr-card">
        <div class="qr-emoji">🎉</div>
        <h2 class="qr-title">¡Mazo completado!</h2>
        <div class="qr-topic">${topicData.name}</div>

        <div class="qr-ring" style="--ring-color:#10b981">
          <svg viewBox="0 0 120 120">
            <circle cx="60" cy="60" r="50" fill="none" stroke="rgba(255,255,255,0.06)" stroke-width="10"/>
            <circle cx="60" cy="60" r="50" fill="none" stroke="#10b981"
              stroke-width="10"
              stroke-dasharray="${2*Math.PI*50}"
              stroke-dashoffset="0"
              stroke-linecap="round"
              transform="rotate(-90 60 60)"
              style="transition:stroke-dashoffset 1s ease"
            />
          </svg>
          <div class="qr-ring-text">
            <span class="qr-pct">100%</span>
            <span class="qr-score-label">${total} tarjetas</span>
          </div>
        </div>

        <div class="qr-msg">Dominaste todas las tarjetas de este tema. ¡Excelente trabajo!</div>

        <div class="qr-actions">
          <button class="qr-btn qr-btn--retry" onclick="startAnki('${spId}',${topicData.num})">
            🔄 Estudiar de nuevo
          </button>
          <button class="qr-btn qr-btn--back" onclick="exitAnki('${spId}','${stateKey}')">
            ← Elegir otro tema
          </button>
        </div>
      </div>
    </div>
  `;
}

function exitAnki(spId, stateKey) {
  delete ankiState[stateKey];
  renderSpecialtySection(spId, 'anki');
}

// ===========================
// INIT
// ===========================
showView('dashboard');
